<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Summer 2026: Three DeFi Dashboards Shut Down in Sequence</text>
  <g font-family="sans-serif">
    <line x1="20" y1="80" x2="660" y2="80" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="90" cy="80" r="8" fill="#38bdf8"/>
    <circle cx="330" cy="80" r="8" fill="#fbbf24"/>
    <circle cx="620" cy="80" r="9" fill="#fb7185"/>
    <text x="90" y="60" fill="#7dd3fc" font-size="13" font-weight="700" text-anchor="middle">June</text>
    <text x="90" y="104" fill="#e4e4e7" font-size="13" text-anchor="middle">TapTools</text>
    <text x="90" y="122" fill="#a1a1aa" font-size="12" text-anchor="middle">Cardano analytics closes</text>
    <text x="330" y="60" fill="#fde68a" font-size="13" font-weight="700" text-anchor="middle">Late Jun–early Jul</text>
